import { create } from 'zustand';

export interface StrategyNode {
  id: string;
  type: 'CONDITION' | 'ACTION';
  x: number;
  y: number;
  data: {
    label: string;
    // CONDITION: targetPrice, operator ('lt' | 'gt')
    targetPrice?: number;
    operator?: 'lt' | 'gt';
    // ACTION: side ('BUY' | 'SELL'), amount
    side?: 'BUY' | 'SELL';
    amount?: number;
  };
}

export interface Connection {
  fromId: string;
  toId: string;
}

export interface TradeLog {
  id: string;
  message: string;
  time: string;
  type: 'BUY' | 'SELL';
}

interface SimulationState {
  balance: number;
  isRunning: boolean;
  currentPrice: number;
  priceHistory: number[];
  nodes: StrategyNode[];
  connections: Connection[];
  logs: TradeLog[];

  toggleSimulation: () => void;
  tick: () => void;
  addNode: (node: StrategyNode) => void;
  updateNodePosition: (id: string, x: number, y: number) => void;
  updateNodeData: (id: string, data: Partial<StrategyNode['data']>) => void;
  connectNodes: (fromId: string, toId: string) => void;
  removeConnection: (fromId: string, toId: string) => void;
}

export const useSimulationStore = create<SimulationState>((set, get) => ({
  balance: 10000,
  isRunning: false,
  currentPrice: 150,
  priceHistory: [150],
  nodes: [],
  connections: [],
  logs: [],

  toggleSimulation: () =>
    set((state) => ({ isRunning: !state.isRunning })),

  tick: () =>
    set((state) => {
      // Random walk: ±0.5% per tick
      const change = state.currentPrice * (Math.random() * 0.01 - 0.005);
      const newPrice = Math.max(1, state.currentPrice + change);
      const price = parseFloat(newPrice.toFixed(2));

      // Evaluate CONDITION -> ACTION connections
      let newBalance = state.balance;
      const firedConnections: string[] = []; // keys "fromId:toId" to remove
      const newLogs: TradeLog[] = [];

      for (const conn of state.connections) {
        const condNode = state.nodes.find(
          (n) => n.id === conn.fromId && n.type === 'CONDITION'
        );
        const actNode = state.nodes.find(
          (n) => n.id === conn.toId && n.type === 'ACTION'
        );
        if (!condNode || !actNode) continue;

        const { operator, targetPrice } = condNode.data;
        const { side, amount } = actNode.data;
        if (targetPrice == null || !operator || !side || !amount) continue;

        // Evaluate condition against new price
        const condMet =
          operator === 'lt' ? price < targetPrice : price > targetPrice;

        if (condMet) {
          const cost = side === 'BUY' ? -amount : amount;
          newBalance = parseFloat((newBalance + cost).toFixed(2));
          firedConnections.push(`${conn.fromId}:${conn.toId}`);

          const now = new Date();
          const timeStr = now.toLocaleTimeString('en-US', { hour12: false });
          newLogs.push({
            id: `${Date.now()}-${Math.random()}`,
            message: `${side} $${amount} @ ${price.toFixed(2)}`,
            time: timeStr,
            type: side,
          });
        }
      }

      // Remove fired connections (fire-once)
      const remainingConnections = state.connections.filter(
        (c) => !firedConnections.includes(`${c.fromId}:${c.toId}`)
      );

      const allLogs = [...newLogs, ...state.logs].slice(0, 50);

      // P&L drift (only if no trade fired this tick)
      if (newLogs.length === 0) {
        const pnl = (Math.random() - 0.495) * 10;
        newBalance = parseFloat((newBalance + pnl).toFixed(2));
      }

      return {
        currentPrice: price,
        balance: newBalance,
        priceHistory: [...state.priceHistory, newPrice].slice(-100),
        connections: remainingConnections,
        logs: allLogs,
      };
    }),

  addNode: (node) =>
    set((state) => ({ nodes: [...state.nodes, node] })),

  updateNodePosition: (id, x, y) =>
    set((state) => ({
      nodes: state.nodes.map((n) => (n.id === id ? { ...n, x, y } : n)),
    })),

  updateNodeData: (id, data) =>
    set((state) => ({
      nodes: state.nodes.map((n) =>
        n.id === id ? { ...n, data: { ...n.data, ...data } } : n
      ),
    })),

  connectNodes: (fromId, toId) =>
    set((state) => {
      // Prevent duplicate connections
      const exists = state.connections.some(
        (c) => c.fromId === fromId && c.toId === toId
      );
      if (exists) return {};
      return { connections: [...state.connections, { fromId, toId }] };
    }),

  removeConnection: (fromId, toId) =>
    set((state) => ({
      connections: state.connections.filter(
        (c) => !(c.fromId === fromId && c.toId === toId)
      ),
    })),
}));
